package internal

import (
	"time"

	"github.com/juju/juju/core/migration"
	coremodelmigration "github.com/juju/juju/core/modelmigration"
)

// ExternalControllerAddress describes an address row to persist for an
// external controller.
type ExternalControllerAddress struct {
	UUID    string
	Address string
}

// ExternalController is the state-layer representation of a third-party
// controller referenced by a migrating model's cross-model relations. Its
// address row UUIDs are generated by the service before it reaches state, so
// the state layer only persists supplied identifiers.
type ExternalController struct {
	UUID           string
	Alias          string
	CACert         string
	Addresses      []ExternalControllerAddress
	ConsumedModels []string
}

// MigrationSpec describes the state-layer data required to record a new source
// export migration.
type MigrationSpec struct {
	MigrationUUID string
	ModelUUID     string

	TargetControllerUUID  string
	TargetControllerAlias string
	TargetAddrs           []ExternalControllerAddress
	TargetCACert          string
	TargetUser            string
	TargetMacaroons       string
	TargetToken           string
	TargetSkipUserChecks  bool
}

// Migration is the state-layer representation of an active export migration.
type Migration struct {
	UUID             string
	Phase            migration.Phase
	PhaseChangedTime time.Time
	Target           TargetInfo
}

// TargetInfo carries target connection details as persisted by state.
type TargetInfo struct {
	ControllerUUID  string
	ControllerAlias string
	Addrs           []string
	CACert          string
	User            string
	Macaroons       string
	Token           string
	SkipUserChecks  bool
}

// SourceControllerInfo is the raw state-layer representation of this
// controller's identity and API address rows.
type SourceControllerInfo struct {
	ControllerUUID  string
	ControllerAlias string
	Addrs           []SourceControllerAddress
	CACert          string
}

// SourceControllerAddress describes a single source controller API address.
type SourceControllerAddress struct {
	ControllerID string
	Address      string
	Scope        string
	IsAgent      bool
}

// MinionReports is the aggregated set of persisted minion phase reports for a
// single migration phase.
type MinionReports struct {
	Phase     migration.Phase
	Succeeded []string
	Failed    []string
}

// MigrationAgents contains the raw names of agents that must report migration
// minion progress for a model.
type MigrationAgents struct {
	Machines     []string
	Units        []string
	Applications []string
}

// OffererModel is kept as an alias for existing modelmigration state code.
type OffererModel = coremodelmigration.OffererModel

// RedirectionTarget carries the target controller identity for the redirect
// snapshot stored in model_migration_redirect. It is the source-side durable
// post-REAP redirect contract, read at login time by the model service.
type RedirectionTarget struct {
	ControllerUUID  string
	ControllerAlias string
	Addresses       []string
	CACert          string
}

// RedirectUserAccess is a single user's captured model access level, stored in
// model_migration_redirect_user for post-REAP login authorization.
type RedirectUserAccess struct {
	UserUUID string
	UserName string
	Access   string
}
